import{_ as i,o as a,c as e,ai as t}from"./chunks/framework.CaiDwmc7.js";const g=JSON.parse('{"title":"MyBatis 与 MyBatis-Plus 核心连环问","description":"","frontmatter":{},"headers":[],"relativePath":"framework/mybatis.md","filePath":"framework/mybatis.md"}'),n={name:"framework/mybatis.md"};function l(r,s,o,d,p,h){return a(),e("div",null,[...s[0]||(s[0]=[t('<h1 id="mybatis-与-mybatis-plus-核心连环问" tabindex="-1">MyBatis 与 MyBatis-Plus 核心连环问 <a class="header-anchor" href="#mybatis-与-mybatis-plus-核心连环问" aria-label="Permalink to “MyBatis 与 MyBatis-Plus 核心连环问”">​</a></h1><hr><h3 id="❓-面试官-mybatis-中-和-的区别是什么-能混用吗" tabindex="-1">❓ 面试官：MyBatis 中 <code>#</code> 和 <code>$</code> 的区别是什么？能混用吗？ <a class="header-anchor" href="#❓-面试官-mybatis-中-和-的区别是什么-能混用吗" aria-label="Permalink to “❓ 面试官：MyBatis 中 # 和 $ 的区别是什么？能混用吗？”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong></p><ul><li><code>#{}</code> 是<strong>预编译处理</strong>（PreparedStatement），参数会被当作一个安全的字符串带引号替换进去，能<strong>绝对防止 SQL 注入</strong>。</li><li><code>${}</code> 是<strong>单纯的字符串拼接</strong>（Statement），原样把参数拼接到 SQL 语句中，<strong>存在严重的 SQL 注入风险</strong>。</li><li>日常开发中 <code>99%</code> 的情况必须用 <code>#{}</code>。</li></ul><p><strong>📝 详细原理解析与例外场景：</strong></p><ol><li><strong>防注入原理（为什么 <code>#</code> 安全？）</strong> 当使用 <code>#{name}</code> 时，MyBatis 会把它解析成 <code>?</code> 占位符： <code>SELECT * FROM user WHERE name = ?</code> 即使你传入的值是 <code>admin&#39; OR &#39;1&#39;=&#39;1</code>，底层 JDBC 会把它当成一个普通字符串常量处理： <code>SELECT * FROM user WHERE name = &#39;admin&#39;&#39; OR &#39;&#39;1&#39;&#39;=&#39;&#39;1&#39;</code>（数据库查不到结果，安全）。 如果用 <code>${}</code>，SQL 变成了 <code>SELECT * FROM user WHERE name = &#39;admin&#39; OR &#39;1&#39;=&#39;1&#39;</code>，导致表全被查出来（危险）。</li><li><strong>什么时候必须用 <code>${}</code>？（核心考点）</strong> 因为 <code>#{}</code> 会自动加引号，所以在<strong>动态传入表名、列名、排序字段</strong>时，只能用 <code>${}</code>。 <ul><li><strong>错误示例</strong>：<code>ORDER BY #{column}</code> -&gt; 变成了 <code>ORDER BY &#39;create_time&#39;</code>（语法错误或失效）。</li><li><strong>正确做法</strong>：<code>ORDER BY ${column}</code>。但为了防注入，必须在 Java 代码里对 <code>column</code> 变量做<strong>白名单校验</strong>（只允许它等于有限的几个英文字段名）。</li></ul></li></ol><hr><h3 id="❓-面试官-mybatis-的一缓和二缓是什么-为什么在分布式项目中大家都会把它们关掉-【中高级】" tabindex="-1">❓ 面试官：MyBatis 的一缓和二缓是什么？为什么在分布式项目中大家都会把它们关掉？【中高级】 <a class="header-anchor" href="#❓-面试官-mybatis-的一缓和二缓是什么-为什么在分布式项目中大家都会把它们关掉-【中高级】" aria-label="Permalink to “❓ 面试官：MyBatis 的一缓和二缓是什么？为什么在分布式项目中大家都会把它们关掉？【中高级】”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong></p><ul><li><strong>一级缓存（本地缓存）</strong>：作用域是同一个 <code>SqlSession</code>，默认<strong>开启</strong>。</li><li><strong>二级缓存（全局缓存）</strong>：作用域是同一个 <code>Mapper</code>（Namespace），默认<strong>关闭</strong>。</li><li><strong>致命坑点</strong>：它们都是基于<strong>单机 JVM 内存</strong>的缓存。在分布式（多台服务器）环境下，会导致极度严重的<strong>脏读问题</strong>，因此企业级开发中通常会禁用 MyBatis 缓存，统一交给 Redis 等专业缓存中间件来做。</li></ul><p><strong>📝 详细踩坑分析（为什么不用？）：</strong> 假设我们部署了 A 和 B 两台订单服务。</p><ol><li><strong>一缓脏读</strong>：一级缓存只在一个 Session 内有效，其实很少引发大问题，但如果我们结合了 Spring 的 <code>@Transactional</code>，整个事务期间共用一个 Session。如果此时另一个线程改了数据库，当前事务内再次查询拿到的还是本地一缓的旧数据（破坏了数据库的隔离级别期望）。通常可以在全局配置里加 <code>localCacheScope=STATEMENT</code> 来关闭一缓。</li><li><strong>二缓灾难</strong>： <ul><li>请求 1 打到 A 服务器，A 查了一次订单表，把数据放入 A 的二级缓存里。</li><li>请求 2 打到 B 服务器，B 执行了 <code>UPDATE</code> 更新了订单表（B 自己清空了自己的缓存，但它无法通知 A）。</li><li>请求 3 又打到 A 服务器，A 会直接从自己的二级缓存里返回<strong>旧数据</strong>！</li><li>所以，MyBatis 的缓存机制太弱（不支持跨 JVM 的缓存失效通知），直接弃用。</li></ul></li></ol><hr><h3 id="❓-面试官-你们项目为什么用-mybatis-plus-它底层是怎么实现那些-crud-接口的" tabindex="-1">❓ 面试官：你们项目为什么用 MyBatis-Plus？它底层是怎么实现那些 CRUD 接口的？ <a class="header-anchor" href="#❓-面试官-你们项目为什么用-mybatis-plus-它底层是怎么实现那些-crud-接口的" aria-label="Permalink to “❓ 面试官：你们项目为什么用 MyBatis-Plus？它底层是怎么实现那些 CRUD 接口的？”">​</a></h3><p><em>频率：🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> MyBatis-Plus（MP）是 MyBatis 的最强增强工具。我们用它主要是为了<strong>消灭那些枯燥的单表 CRUD XML 配置</strong>。它底层利用了<strong>自定义的 SQL 注入器（ISqlInjector）</strong>，在项目启动时通过反射读取实体类，自动在内存中拼接并注入这些基础的 SQL 语句，避免了我们手动去写 Mapper。</p><p><strong>📝 核心亮点（面试怎么吹？）：</strong></p><ol><li><strong>开发效率起飞</strong>：Mapper 接口继承 <code>BaseMapper</code>，Service 继承 <code>IService</code>，瞬间拥有了几十个常用的增删改查和分页方法，一行 XML 都不用写。</li><li><strong>强大的 Wrapper 构造器</strong>： 以前写多条件动态查询：<div class="language-xml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">where</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">if</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> test</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;name != null&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt; AND name = #{name} &lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">where</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div>现在用 MP 的 <code>LambdaQueryWrapper</code>（极其优雅且防防手误拼错字段）：<div class="language-java line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">LambdaQueryWrapper&lt; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">User</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &gt; query </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> new</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> LambdaQueryWrapper&lt;&gt;();</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">query.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">eq</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(StringUtils.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">isNotBlank</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(name), User</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">getName, name);</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">userMapper.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">selectList</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(query);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></li><li><strong>自带极好用的插件</strong>： <ul><li><strong>分页插件（PaginationInnerInterceptor）</strong>：物理分页，底层根据不同的数据库方言（MySQL 用 limit，Oracle 用 rownum）自动拼接。</li><li><strong>乐观锁插件（OptimisticLockerInnerInterceptor）</strong>：只需给实体的 <code>version</code> 字段打上 <code>@Version</code> 注解，执行 update 时自动帮你带上版本号条件，解决并发更新丢失的问题。</li><li><strong>自动填充插件</strong>：配合 <code>@TableField(fill = FieldFill.INSERT)</code>，在插入或修改时，自动帮你把 <code>create_time</code> 和 <code>update_time</code> 赋上系统时间，再也不用手动 set 了。</li></ul></li></ol>',21)])])}const k=i(n,[["render",l]]);export{g as __pageData,k as default};
